import { boolean, integer, pgTable, varchar, serial, text, timestamp, unique, doublePrecision, date, json, index, primaryKey } from "drizzle-orm/pg-core";
import { getCycleTables } from "./cycle-tables";

// ---------------------------------------------------------------------------
// Per-cycle tables
//
// All cycle-specific tables (`gp_cycle{n}`, `cycle{n}_gf`, long-term lists,
// source reports, skymap, proposals) are generated by the factory in
// `cycle-tables.ts`. The named exports below preserve the historical Cycle-2
// names so existing imports keep working unchanged. To query another cycle at
// runtime use `getCycleTables(n)` instead of these aliases.
// ---------------------------------------------------------------------------
export const cycle2AntiTooProposal = getCycleTables(2).antiTooProposal;
export const gpCycle2Proposal = getCycleTables(2).proposal;
export const gpCycle2 = getCycleTables(2).gp;
export const cycle2GF = getCycleTables(2).gf;
export const longTermObservationListCycle2 = getCycleTables(2).longTerm;
export const longTermObservationListCycle2GF = getCycleTables(2).longTermGf;
export const gpCycle2SourceReports = getCycleTables(2).sourceReports;
export const cycle2SkymapSources = getCycleTables(2).skymapSources;
export const cycle2SkymapSchedule = getCycleTables(2).skymapSchedule;

export const usersTable = pgTable("users", {
  id: integer().primaryKey().generatedAlwaysAsIdentity(),
  name: varchar({ length: 255 }).notNull(),
	username: varchar({ length: 255 }).notNull().unique(),
  age: integer().default(0).notNull(),
  email: varchar({ length: 255 }).notNull().unique(),
	passwordHash: text("password_hash").notNull().default(""),
  vip: boolean().notNull().default(false),
  role: varchar("role", { length: 16 }).notNull().default("viewer"),
  allowShortTermPlanning: boolean("allow_short_term_planning").notNull().default(false),
});

